var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아저씨! 민우 아저씨 있어요?!","JPN":"おじさん！　マツダおじさんいるー？","ENG":"Mr. Minwoo! Are you here?!","TWN":"叔叔！民宇叔叔在嗎？！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐야, 없네? 꼭 필요할 때는 자리비움이라니까?","JPN":"なんだ、いないんだ。いつも必要な時に限っていないんだから。","ENG":"Huh? He's not here? Ugh, he's never around when you need him!","TWN":"什麼嘛～不在喔？每次需要他的時候就找不到人！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그건 네가 시도 때도 없이 찾아오니까 그렇게 느끼는 거지.","JPN":"そりゃあんたがひっきりなしに来るからそう思うだけだろ。","ENG":"That's only because you come here all the time.","TWN":"那是因為你三不五時就來報到，才會有這種感覺。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여긴 편의점이다, 레이첼. 물건을 파는 데지 주민 센터가 아니야.","JPN":"ここはコンビニだ、レイチェル。物を売る場所で公民館じゃあない。","ENG":"This is a convenience store, Rachel. We sell stuff here. We're not your mom.","TWN":"我說瑞秋，這裡是便利商店，不是里民活動中心好嗎！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"편의점 점원이 왜 그렇게 까칠해요. 사포라도 말아 잡수셨나.","JPN":"コンビニの店員がそんな無愛想でいいんですか？　そんなにピリピリしちゃって。","ENG":"Geez, why are you so grouchy? Do you live in a trash can or something?","TWN":"便利商店店員怎麼這麼愛頂嘴，人家講一句你回十句。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다른 건 몰라도 제가 이 가게에서 스프레이 하나는 잘 팔아 주거든요? 손님 대접은 해 주시죠?","JPN":"他はどうかわからないけど、この店のスプレーに関してはアタシが太客なんですけど！　ちゃんとお客様として接してください！","ENG":"You know how many spray cans I've bought at this place? That's no way to treat a paying customer.","TWN":"其他我不敢說，起碼我也在這家店裡消費不少噴漆好嗎？可以來點客人的待遇嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"안 그래도 주인장이 그러더군.","JPN":"ああ、そういや店長も言ってたな。","ENG":"That's right, the manager told me.","TWN":"人家主人也有跟我抱怨好嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"네가 안 졸라댔으면 그 잡동사니들 들여놓는 일도 없었다고 말이야.","JPN":"あんたがせがまなければ、あんなガラクタを仕入れることもなかったってな。","ENG":"If it wasn't for your little tantrum, he'd never stock that junk.","TWN":"他說要不是你一直吵，他才不會讓你畫那些有的沒的。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"체엣. 뭐래, 그 할배는. 바가지도 실컷 씌워 먹는 주제에.","JPN":"チッ、なんなのあのジジイは。ぼったくり価格で売りつけてるくせに。","ENG":"Hmph. That old geezer's full of it. He's always ripping me off anyway.","TWN":"嗟！說什麼呢！那位爺爺得了便宜還賣乖！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"수다 친구 찾으러 왔다면 다음에 다시 와.","JPN":"おしゃべりの相手がほしいだけなら今度にしろ。","ENG":"If you're here to make small talk, you'll have to come back later.","TWN":"你想來找人聊天的話，晚點再來吧。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"자경단 녀석들이 도와달라고 해서 합류하러 가야 하니까.","JPN":"俺は自警団のやつらに頼まれたからこれから合流しに行く。","ENG":"The neighborhood watch guys needed a hand.","TWN":"自衛隊的人來找我幫忙，我現在要去跟他們會合。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 내 정신 좀 봐! 혹시 그 애 못 봤어요?","JPN":"あ、そうだ、アタシったら！　あの子見てないですか？","ENG":"Oh, I almost forgot! Have you seen that kid by any chance?","TWN":"哎呀！看我這記性！我是要問你有看到她嗎？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"여기서 신세 지는 동안 네가 기저귀 들고 쫓아다니는 애만 일곱 명은 넘게 봤다.","JPN":"ここで働き始めてから、あんたがオムツを持って追いかけてた子どもだけでも7人以上は知っているんだが。","ENG":"I must have seen at least half dozen of those kids you're always chasing around here.","TWN":"我每天看你拿著尿布追著一堆人跑，誰知道你在問誰？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"언제 그렇게 보고 계셨대. 음흉하게시리.","JPN":"そんなにアタシのことを見てたんですか？　いやらしい。","ENG":"Oh, so you've been keeping tabs? Creepy.","TWN":"就是那個每次眼神都很不懷好意的那個嘛！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……급한 볼일 아니면 그만 가라.","JPN":"……他に用事がないなら帰ってくれ。","ENG":"...If this isn't urgent, get lost already.","TWN":"……沒事的話就快走吧！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그 왜 있잖아요, 머리에 이상한 접시 달고 다니는 여자애.","JPN":"用事はちゃんとあります。あの子ですよ、頭に変な皿をつけてる女の子。","ENG":"Well, you know, the girl with the weird plates on her head?","TWN":"我是說真的啦！頭上掛著奇怪盤子的女生！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……<color=#ffd34c>호라이즌</color> 말이군.","JPN":"……<color=#ffd34c>ホライズン</color>のことか。","ENG":"You mean… <color=#ffd34c>Horizon</color>.","TWN":"……你是說<color=#ffd34c>地平線</color>喔？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그 애라면 점심 때 윤활유 한 통 사서 4번가 방향으로 갔다.","JPN":"あいつなら昼頃に潤滑油を一缶買って4番街の方向へ行ったぞ。","ENG":"She bought a can of lubricant at lunch and headed to 4th Avenue.","TWN":"她中午的時候來買了一瓶潤滑油，就往第四大道的方向離開啦。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아마 늘 있던 곳에 있겠지.","JPN":"たぶんいつもの場所にいるだろう。","ENG":"She's probably where she is.","TWN":"應該在老地方吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이 아저씨 미쳤나 봐! 걔를 거기 또 혼자 보내면 어떡해요! 무슨 일 나면 어쩌려고!","JPN":"おじさん、正気なの？　また一人であそこに行かせて！　何かあったらどうすんですか！？","ENG":"Are you out of your mind?! You can't let her go there all by herself again! What if something goes wrong?!","TWN":"這位大叔你腦袋正常嗎？！你怎麼可以又讓她自己去那個地方，萬一發生什麼事怎麼辦！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"글쎄, 그 애 때문에 호들갑 떠는 사람은 이 동네에 너 혼자뿐인 것 같은데.","JPN":"まあ、あいつのことで騒ぐのはこの町にあんた一人だけなんだが。","ENG":"Hmm, I don't know. You seem to be the only person in the neighborhood making a fuss over her.","TWN":"會嗎？我看這裡會擔心她的人應該只有你吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아니걸랑요? 지금 애 없어졌다고 고아원이 발칵 뒤집혔걸랑요?","JPN":"違いますよ！　あの子がいなくなって今孤児院が大騒ぎになっていますよ！？","ENG":"That's not true! The orphanage is going crazy because she vanished!","TWN":"才不是咧！育幼院現在正找人找得人仰馬翻好嗎！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이상하군. 내가 자경단 사람들한테 같이 찾아달라고 부탁받은 아이는 한 명뿐이다.","JPN":"おかしいな。俺が自警団に一緒に探してくれと頼まれた子どもは一人だけだ。","ENG":"Strange. The neighborhood watch only asked me to help find one kid.","TWN":"奇怪，自衛隊明明只有拜託我幫忙找一個孩子。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"술래잡기를 하던 고아원의 여자아이. 이름이 엠마였지, 아마.","JPN":"鬼ごっこをしていた孤児院の女の子。名前はエマだったな、確か。","ENG":"A girl from the orphanage went missing while playing hide-and-seek. Her name is Emma, if I recall correctly.","TWN":"是一個在玩捉迷藏的育幼院女生，好像叫什麼愛瑪的？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"원장님이 신고할 때 깜빡하고 빠뜨리셨겠죠. 머리숱만큼 뇌세포도 허전한 꼰대니까.","JPN":"院長が通報する時うっかりしただけでしょ。毛量と同じくらい脳細胞もスカスカのジジイなんだから。","ENG":"The headmaster must have forgot to include Horizon in the missing persons report. That geezer's as short on brain cells as he is on hair.","TWN":"一定是院長在通報的時候漏掉了啦！畢竟他已經是個腦細胞和髮量成正比的老頑固。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"원장님한테 너무 틱틱거리지 마. 여기 난민지구에서 그나마 애들 챙기는 사람이야.","JPN":"院長にあまりあたるな。この難民地区で子どもたちの面倒を見てくれる人だ。","ENG":"Don't be so harsh on him. He's one of the few folks who give a damn about children in this refugee district.","TWN":"你對院長說話不要那麼難聽，好歹他也是這難民區裡少數會照顧孩子們的人。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으, 닭살 돋게 설교는.","JPN":"説教はやめてください！　似合わなさすぎて引く。","ENG":"Ugh, save your cheesy lecture for someone else.","TWN":"呃，雞皮疙瘩掉滿地。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"지저분한 수염이나 깎으셔! 메롱!","JPN":"その汚いあごひげでもどうにかしたらどうですか？　べーー。","ENG":"Why don't you just save off that nasty beard? Cuz ya boring.","TWN":"先把你自己的鬍子刮好啦！ㄌㄩㄝ！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어? 이 스프레이 느낌 있네? 외상 달아도 되죠?","JPN":"お、このスプレーいい色なんじゃない？　ツケでいいですよね？","ENG":"Huh? Now this spray's got some pizzazz. Can I put this on my tab?","TWN":"喔？這罐噴漆感覺不錯喔？可以賒帳吧？"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"알려 줘서 고마워요, 아저씨! 나 먼저 갈게요!","JPN":"とにかく教えてくれてありがとう！　探しに行きますね！","ENG":"Thanks for the tip by the way! I'd better get going now!","TWN":"謝謝叔叔告訴我這麼多人生大道理，那我先走囉～！"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"꽤 잘 다듬었다고 생각했는데, 애들 눈엔 영 아닌가 보군.","JPN":"ちゃんと整えたつもりなんだが、子どもの目には汚く見えるのか。","ENG":"I thought I kept myself well-groomed… I guess kids today don't appreciate it.","TWN":"我覺得我刮得滿好的啊，但孩子們好像不這麼覺得。"},"stage":{"bg":"STORE2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"잊지 마, 호라이즌.","JPN":"忘れるな……ホライズン。","ENG":"Don't forget, Horizon.","TWN":"記住，地平線，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"우리가, 내가 너를 만든 건…….","JPN":"私たちが、私があなたを作ったのは……","ENG":"We… I made you because…","TWN":"是我們…是我創造你的……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};